// 환경변수에서 채널별 노트북 생성 항목 파싱
// TOPIC_CHANNELS 형식: "채널이름/채널ID+채널이름/채널ID+..."
// 예: "노마드코더/UCUpJs89fSBXNolQGOYKn0YQ+조코딩/UCQNE2JmbasNYbjGAcuBiRRg"
// 채널당 독립 노트북 1개 생성
const raw = $env.TOPIC_CHANNELS || '';
if (!raw.trim()) return [{ json: { skip: true, reason: 'TOPIC_CHANNELS 미설정' } }];

const today = new Date().toISOString().slice(0, 10);

const items = [];
for (const ch of raw.split('+')) {
  const slashIdx = ch.indexOf('/');
  if (slashIdx < 0) continue;
  const channelName = ch.slice(0, slashIdx).trim();
  const channelId   = ch.slice(slashIdx + 1).trim();
  if (!channelName || !channelId) continue;
  items.push({
    channelId: channelId,
    channelName: channelName,
    notebookName: `${channelName} ${today}`,
  });
}

if (items.length === 0) return [{ json: { skip: true, reason: '파싱된 채널 없음' } }];
return items.map(t => ({ json: t }));

const result = $input.item.json;
const channelId = $input.item.json.channel_id || '(unknown)';

if (result.status === 'success') {
  console.log(`[WF-10] ✅ 노트북 생성 완료: channel_id=${channelId} → ${result.notebook_url}`);
} else {
  console.error(`[WF-10] ❌ 노트북 생성 실패: channel_id=${channelId} — ${result.error}`);
}

return [{ json: result }];
